import { useEffect, useRef } from 'react';

// Хук предназначен для запоминания значения функционального компонента, вычисленного во время предыдущего рендеринга.
export const usePrevious = <T>(value: T): T => {
	const ref = useRef<T | undefined>(undefined);

	useEffect(() => {
		ref.current = value;
	}, [value]);

	return ref.current;
};
